1	//! Threads that can borrow variables from the stack.
2	//!
3	//! Create a scope when spawned threads need to access variables on the stack:
4	//!
5	//! ```
6	//! use crossbeam_utils::thread;
7	//!
8	//! let people = vec![
9	//!     "Alice".to_string(),
10	//!     "Bob".to_string(),
11	//!     "Carol".to_string(),
12	//! ];
13	//!
14	//! thread::scope(|s| {
15	//!     for person in &people {
16	//!         s.spawn(move |_| {
17	//!             println!("Hello, {}!", person);
18	//!         });
19	//!     }
20	//! }).unwrap();
21	//! ```
22	//!
23	//! # Why scoped threads?
24	//!
25	//! Suppose we wanted to re-write the previous example using plain threads:
26	//!
27	//! ```compile_fail,E0597
28	//! use std::thread;
29	//!
30	//! let people = vec![
31	//!     "Alice".to_string(),
32	//!     "Bob".to_string(),
33	//!     "Carol".to_string(),
34	//! ];
35	//!
36	//! let mut threads = Vec::new();
37	//!
38	//! for person in &people {
39	//!     threads.push(thread::spawn(move || {
40	//!         println!("Hello, {}!", person);
41	//!     }));
42	//! }
43	//!
44	//! for thread in threads {
45	//!     thread.join().unwrap();
46	//! }
47	//! ```
48	//!
49	//! This doesn't work because the borrow checker complains about `people` not living long enough:
50	//!
51	//! ```text
52	//! error[E0597]: `people` does not live long enough
53	//!   --> src/main.rs:12:20
54	//!    |
55	//! 12 |     for person in &people {
56	//!    |                    ^^^^^^ borrowed value does not live long enough
57	//! ...
58	//! 21 | }
59	//!    | - borrowed value only lives until here
60	//!    |
61	//!    = note: borrowed value must be valid for the static lifetime...
62	//! ```
63	//!
64	//! The problem here is that spawned threads are not allowed to borrow variables on stack because
65	//! the compiler cannot prove they will be joined before `people` is destroyed.
66	//!
67	//! Scoped threads are a mechanism to guarantee to the compiler that spawned threads will be joined
68	//! before the scope ends.
69	//!
70	//! # How scoped threads work
71	//!
72	//! If a variable is borrowed by a thread, the thread must complete before the variable is
73	//! destroyed. Threads spawned using [`std::thread::spawn`] can only borrow variables with the
74	//! `'static` lifetime because the borrow checker cannot be sure when the thread will complete.
75	//!
76	//! A scope creates a clear boundary between variables outside the scope and threads inside the
77	//! scope. Whenever a scope spawns a thread, it promises to join the thread before the scope ends.
78	//! This way we guarantee to the borrow checker that scoped threads only live within the scope and
79	//! can safely access variables outside it.
80	//!
81	//! # Nesting scoped threads
82	//!
83	//! Sometimes scoped threads need to spawn more threads within the same scope. This is a little
84	//! tricky because argument `s` lives *inside* the invocation of `thread::scope()` and as such
85	//! cannot be borrowed by scoped threads:
86	//!
87	//! ```compile_fail,E0521
88	//! use crossbeam_utils::thread;
89	//!
90	//! thread::scope(|s| {
91	//!     s.spawn(|_| {
92	//!         // Not going to compile because we're trying to borrow `s`,
93	//!         // which lives *inside* the scope! :(
94	//!         s.spawn(|_| println!("nested thread"));
95	//!     });
96	//! });
97	//! ```
98	//!
99	//! Fortunately, there is a solution. Every scoped thread is passed a reference to its scope as an
100	//! argument, which can be used for spawning nested threads:
101	//!
102	//! ```
103	//! use crossbeam_utils::thread;
104	//!
105	//! thread::scope(|s| {
106	//!     // Note the `|s|` here.
107	//!     s.spawn(|s| {
108	//!         // Yay, this works because we're using a fresh argument `s`! :)
109	//!         s.spawn(|_| println!("nested thread"));
110	//!     });
111	//! }).unwrap();
112	//! ```
113	
114	use alloc::{boxed::Box, string::String, sync::Arc, vec::Vec};
115	use core::{fmt, marker::PhantomData, mem};
116	use std::{io, panic, sync::Mutex, thread};
117	
118	use crate::sync::WaitGroup;
119	
120	type SharedVec<T> = Arc<Mutex<Vec<T>>>;
121	type SharedOption<T> = Arc<Mutex<Option<T>>>;
122	
123	/// Creates a new scope for spawning threads.
124	///
125	/// All child threads that haven't been manually joined will be automatically joined just before
126	/// this function invocation ends. If all joined threads have successfully completed, `Ok` is
127	/// returned with the return value of `f`. If any of the joined threads has panicked, an `Err` is
128	/// returned containing errors from panicked threads. Note that if panics are implemented by
129	/// aborting the process, no error is returned; see the notes of [std::panic::catch_unwind].
130	///
131	/// **Note:** Since Rust 1.63, this function is soft-deprecated in favor of the more efficient [`std::thread::scope`].
132	///
133	/// # Examples
134	///
135	/// ```
136	/// use crossbeam_utils::thread;
137	///
138	/// let var = vec![1, 2, 3];
139	///
140	/// thread::scope(|s| {
141	///     s.spawn(|_| {
142	///         println!("A child thread borrowing `var`: {:?}", var);
143	///     });
144	/// }).unwrap();
145	/// ```
146	pub fn scope<'env, F, R>(f: F) -> thread::Result<R>
147	where
148	    F: FnOnce(&Scope<'env>) -> R,
149	{
150	    struct AbortOnPanic;
151	    impl Drop for AbortOnPanic {
152	        fn drop(&mut self) {
153	            if thread::panicking() {
154	                std::process::abort();
155	            }
156	        }
157	    }
158	
159	    let wg = WaitGroup::new();
160	    let scope = Scope::<'env> {
161	        handles: SharedVec::default(),
162	        wait_group: wg.clone(),
163	        _marker: PhantomData,
164	    };
165	
166	    // Execute the scoped function, but catch any panics.
167	    let result = panic::catch_unwind(panic::AssertUnwindSafe(|| f(&scope)));
168	
169	    // If an unwinding panic occurs before all threads are joined
170	    // promote it to an aborting panic to prevent any threads from escaping the scope.
171	    let guard = AbortOnPanic;
172	
173	    // Wait until all nested scopes are dropped.
174	    drop(scope.wait_group);
175	    wg.wait();
176	
177	    // Join all remaining spawned threads.
178	    let panics: Vec<_> = scope
179	        .handles
180	        .lock()
181	        .unwrap()
182	        // Filter handles that haven't been joined, join them, and collect errors.
183	        .drain(..)
184	        .filter_map(|handle| handle.lock().unwrap().take())
185	        .filter_map(|handle| handle.join().err())
186	        .collect();
187	
188	    mem::forget(guard);
189	
190	    // If `f` has panicked, resume unwinding.
191	    // If any of the child threads have panicked, return the panic errors.
192	    // Otherwise, everything is OK and return the result of `f`.
193	    match result {
194	        Err(err) => panic::resume_unwind(err),
195	        Ok(res) => {
196	            if panics.is_empty() {
197	                Ok(res)
198	            } else {
199	                Err(Box::new(panics))
200	            }
201	        }
202	    }
203	}
204	
205	/// A scope for spawning threads.
206	pub struct Scope<'env> {
207	    /// The list of the thread join handles.
208	    handles: SharedVec<SharedOption<thread::JoinHandle<()>>>,
209	
210	    /// Used to wait until all subscopes all dropped.
211	    wait_group: WaitGroup,
212	
213	    /// Borrows data with invariant lifetime `'env`.
214	    _marker: PhantomData<&'env mut &'env ()>,
215	}
216	
217	unsafe impl Sync for Scope<'_> {}
218	
219	impl<'env> Scope<'env> {
220	    /// Spawns a scoped thread.
221	    ///
222	    /// This method is similar to the [`spawn`] function in Rust's standard library. The difference
223	    /// is that this thread is scoped, meaning it's guaranteed to terminate before the scope exits,
224	    /// allowing it to reference variables outside the scope.
225	    ///
226	    /// The scoped thread is passed a reference to this scope as an argument, which can be used for
227	    /// spawning nested threads.
228	    ///
229	    /// The returned [handle](ScopedJoinHandle) can be used to manually
230	    /// [join](ScopedJoinHandle::join) the thread before the scope exits.
231	    ///
232	    /// This will create a thread using default parameters of [`ScopedThreadBuilder`], if you want to specify the
233	    /// stack size or the name of the thread, use this API instead.
234	    ///
235	    /// [`spawn`]: std::thread::spawn
236	    ///
237	    /// # Panics
238	    ///
239	    /// Panics if the OS fails to create a thread; use [`ScopedThreadBuilder::spawn`]
240	    /// to recover from such errors.
241	    ///
242	    /// # Examples
243	    ///
244	    /// ```
245	    /// use crossbeam_utils::thread;
246	    ///
247	    /// thread::scope(|s| {
248	    ///     let handle = s.spawn(|_| {
249	    ///         println!("A child thread is running");
250	    ///         42
251	    ///     });
252	    ///
253	    ///     // Join the thread and retrieve its result.
254	    ///     let res = handle.join().unwrap();
255	    ///     assert_eq!(res, 42);
256	    /// }).unwrap();
257	    /// ```
258	    pub fn spawn<'scope, F, T>(&'scope self, f: F) -> ScopedJoinHandle<'scope, T>
259	    where
260	        F: FnOnce(&Scope<'env>) -> T,
261	        F: Send + 'env,
262	        T: Send + 'env,
263	    {
264	        self.builder()
265	            .spawn(f)
266	            .expect("failed to spawn scoped thread")
267	    }
268	
269	    /// Creates a builder that can configure a thread before spawning.
270	    ///
271	    /// # Examples
272	    ///
273	    /// ```
274	    /// use crossbeam_utils::thread;
275	    ///
276	    /// thread::scope(|s| {
277	    ///     s.builder()
278	    ///         .spawn(|_| println!("A child thread is running"))
279	    ///         .unwrap();
280	    /// }).unwrap();
281	    /// ```
282	    pub fn builder<'scope>(&'scope self) -> ScopedThreadBuilder<'scope, 'env> {
283	        ScopedThreadBuilder {
284	            scope: self,
285	            builder: thread::Builder::new(),
286	        }
287	    }
288	}
289	
290	impl fmt::Debug for Scope<'_> {
291	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
292	        f.pad("Scope { .. }")
293	    }
294	}
