296	/// Configures the properties of a new thread.
297	///
298	/// The two configurable properties are:
299	///
300	/// - [`name`]: Specifies an [associated name for the thread][naming-threads].
301	/// - [`stack_size`]: Specifies the [desired stack size for the thread][stack-size].
302	///
303	/// The [`spawn`] method will take ownership of the builder and return an [`io::Result`] of the
304	/// thread handle with the given configuration.
305	///
306	/// The [`Scope::spawn`] method uses a builder with default configuration and unwraps its return
307	/// value. You may want to use this builder when you want to recover from a failure to launch a
308	/// thread.
309	///
310	/// # Examples
311	///
312	/// ```
313	/// use crossbeam_utils::thread;
314	///
315	/// thread::scope(|s| {
316	///     s.builder()
317	///         .spawn(|_| println!("Running a child thread"))
318	///         .unwrap();
319	/// }).unwrap();
320	/// ```
321	///
322	/// [`name`]: ScopedThreadBuilder::name
323	/// [`stack_size`]: ScopedThreadBuilder::stack_size
324	/// [`spawn`]: ScopedThreadBuilder::spawn
325	/// [`io::Result`]: std::io::Result
326	/// [naming-threads]: std::thread#naming-threads
327	/// [stack-size]: std::thread#stack-size
328	#[must_use = "must eventually spawn the thread"]
329	#[derive(Debug)]
330	pub struct ScopedThreadBuilder<'scope, 'env> {
331	    scope: &'scope Scope<'env>,
332	    builder: thread::Builder,
333	}
334	
335	impl<'scope, 'env> ScopedThreadBuilder<'scope, 'env> {
336	    /// Sets the name for the new thread.
337	    ///
338	    /// The name must not contain null bytes (`\0`).
339	    ///
340	    /// For more information about named threads, see [here][naming-threads].
341	    ///
342	    /// # Examples
343	    ///
344	    /// ```
345	    /// use crossbeam_utils::thread;
346	    /// use std::thread::current;
347	    ///
348	    /// thread::scope(|s| {
349	    ///     s.builder()
350	    ///         .name("my thread".to_string())
351	    ///         .spawn(|_| assert_eq!(current().name(), Some("my thread")))
352	    ///         .unwrap();
353	    /// }).unwrap();
354	    /// ```
355	    ///
356	    /// [naming-threads]: std::thread#naming-threads
357	    pub fn name(mut self, name: String) -> Self {
358	        self.builder = self.builder.name(name);
359	        self
360	    }
361	
362	    /// Sets the size of the stack for the new thread.
363	    ///
364	    /// The stack size is measured in bytes.
365	    ///
366	    /// For more information about the stack size for threads, see [here][stack-size].
367	    ///
368	    /// # Examples
369	    ///
370	    /// ```
371	    /// use crossbeam_utils::thread;
372	    ///
373	    /// thread::scope(|s| {
374	    ///     s.builder()
375	    ///         .stack_size(32 * 1024)
376	    ///         .spawn(|_| println!("Running a child thread"))
377	    ///         .unwrap();
378	    /// }).unwrap();
379	    /// ```
380	    ///
381	    /// [stack-size]: std::thread#stack-size
382	    pub fn stack_size(mut self, size: usize) -> Self {
383	        self.builder = self.builder.stack_size(size);
384	        self
385	    }
386	
387	    /// Spawns a scoped thread with this configuration.
388	    ///
389	    /// The scoped thread is passed a reference to this scope as an argument, which can be used for
390	    /// spawning nested threads.
391	    ///
392	    /// The returned handle can be used to manually join the thread before the scope exits.
393	    ///
394	    /// # Errors
395	    ///
396	    /// Unlike the [`Scope::spawn`] method, this method yields an
397	    /// [`io::Result`] to capture any failure to create the thread at
398	    /// the OS level.
399	    ///
400	    /// [`io::Result`]: std::io::Result
401	    ///
402	    /// # Panics
403	    ///
404	    /// Panics if a thread name was set and it contained null bytes.
405	    ///
406	    /// # Examples
407	    ///
408	    /// ```
409	    /// use crossbeam_utils::thread;
410	    ///
411	    /// thread::scope(|s| {
412	    ///     let handle = s.builder()
413	    ///         .spawn(|_| {
414	    ///             println!("A child thread is running");
415	    ///             42
416	    ///         })
417	    ///         .unwrap();
418	    ///
419	    ///     // Join the thread and retrieve its result.
420	    ///     let res = handle.join().unwrap();
421	    ///     assert_eq!(res, 42);
422	    /// }).unwrap();
423	    /// ```
424	    pub fn spawn<F, T>(self, f: F) -> io::Result<ScopedJoinHandle<'scope, T>>
425	    where
426	        F: FnOnce(&Scope<'env>) -> T,
427	        F: Send + 'env,
428	        T: Send + 'env,
429	    {
430	        // The result of `f` will be stored here.
431	        let result = SharedOption::default();
432	
433	        // Spawn the thread and grab its join handle and thread handle.
434	        let (handle, thread) = {
435	            let result = Arc::clone(&result);
436	
437	            // A clone of the scope that will be moved into the new thread.
438	            let scope = Scope::<'env> {
439	                handles: Arc::clone(&self.scope.handles),
440	                wait_group: self.scope.wait_group.clone(),
441	                _marker: PhantomData,
442	            };
443	
444	            // Spawn the thread.
445	            let handle = {
446	                let closure = move || {
447	                    // Make sure the scope is inside the closure with the proper `'env` lifetime.
448	                    let scope: Scope<'env> = scope;
449	
450	                    // Run the closure.
451	                    let res = f(&scope);
452	
453	                    // Store the result if the closure didn't panic.
454	                    *result.lock().unwrap() = Some(res);
455	                };
456	
457	                // Allocate `closure` on the heap and erase the `'env` bound.
458	                let closure: Box<dyn FnOnce() + Send + 'env> = Box::new(closure);
459	                let closure: Box<dyn FnOnce() + Send + 'static> =
460	                    unsafe { mem::transmute(closure) };
461	
462	                // Finally, spawn the closure.
463	                self.builder.spawn(closure)?
464	            };
465	
466	            let thread = handle.thread().clone();
467	            let handle = Arc::new(Mutex::new(Some(handle)));
468	            (handle, thread)
469	        };
470	
471	        // Add the handle to the shared list of join handles.
472	        self.scope.handles.lock().unwrap().push(Arc::clone(&handle));
473	
474	        Ok(ScopedJoinHandle {
475	            handle,
476	            result,
477	            thread,
478	            _marker: PhantomData,
479	        })
480	    }
481	}
482	
483	unsafe impl<T> Send for ScopedJoinHandle<'_, T> {}
484	unsafe impl<T> Sync for ScopedJoinHandle<'_, T> {}
485	
486	/// A handle that can be used to join its scoped thread.
487	///
488	/// This struct is created by the [`Scope::spawn`] method and the
489	/// [`ScopedThreadBuilder::spawn`] method.
490	pub struct ScopedJoinHandle<'scope, T> {
491	    /// A join handle to the spawned thread.
492	    handle: SharedOption<thread::JoinHandle<()>>,
493	
494	    /// Holds the result of the inner closure.
495	    result: SharedOption<T>,
496	
497	    /// A handle to the spawned thread.
498	    thread: thread::Thread,
499	
500	    /// Borrows the parent scope with lifetime `'scope`.
501	    _marker: PhantomData<&'scope ()>,
502	}
503	
504	impl<T> ScopedJoinHandle<'_, T> {
505	    /// Waits for the thread to finish and returns its result.
506	    ///
507	    /// If the child thread panics, an error is returned. Note that if panics are implemented by
508	    /// aborting the process, no error is returned; see the notes of [std::panic::catch_unwind].
509	    ///
510	    /// # Panics
511	    ///
512	    /// This function may panic on some platforms if a thread attempts to join itself or otherwise
513	    /// may create a deadlock with joining threads.
514	    ///
515	    /// # Examples
516	    ///
517	    /// ```
518	    /// use crossbeam_utils::thread;
519	    ///
520	    /// thread::scope(|s| {
521	    ///     let handle1 = s.spawn(|_| println!("I'm a happy thread :)"));
522	    ///     let handle2 = s.spawn(|_| panic!("I'm a sad thread :("));
523	    ///
524	    ///     // Join the first thread and verify that it succeeded.
525	    ///     let res = handle1.join();
526	    ///     assert!(res.is_ok());
527	    ///
528	    ///     // Join the second thread and verify that it panicked.
529	    ///     let res = handle2.join();
530	    ///     assert!(res.is_err());
531	    /// }).unwrap();
532	    /// ```
533	    pub fn join(self) -> thread::Result<T> {
534	        // Take out the handle. The handle will surely be available because the root scope waits
535	        // for nested scopes before joining remaining threads.
536	        let handle = self.handle.lock().unwrap().take().unwrap();
537	
538	        // Join the thread and then take the result out of its inner closure.
539	        handle
540	            .join()
541	            .map(|()| self.result.lock().unwrap().take().unwrap())
542	    }
543	
544	    /// Returns a handle to the underlying thread.
545	    ///
546	    /// # Examples
547	    ///
548	    /// ```
549	    /// use crossbeam_utils::thread;
550	    ///
551	    /// thread::scope(|s| {
552	    ///     let handle = s.spawn(|_| println!("A child thread is running"));
553	    ///     println!("The child thread ID: {:?}", handle.thread().id());
554	    /// }).unwrap();
555	    /// ```
556	    pub fn thread(&self) -> &thread::Thread {
557	        &self.thread
558	    }
559	}
560	
561	/// Unix-specific extensions.
562	#[cfg(unix)]
563	pub mod unix {
564	    use std::os::unix::thread::JoinHandleExt as _;
565	    #[doc(no_inline)]
566	    pub use std::os::unix::thread::RawPthread;
567	
568	    use super::ScopedJoinHandle;
569	
570	    mod sealed {
571	        pub trait Sealed {}
572	    }
573	
574	    /// Unix-specific extensions to [`ScopedJoinHandle`].
575	    pub trait JoinHandleExt: sealed::Sealed {
576	        /// Extracts the raw pthread_t without taking ownership
577	        fn as_pthread_t(&self) -> RawPthread;
578	
579	        /// Consumes the thread, returning the raw pthread_t
580	        ///
581	        /// This function **transfers ownership** of the underlying pthread_t to
582	        /// the caller. Callers are then the unique owners of the pthread_t and
583	        /// must either detach or join the pthread_t once it's no longer needed.
584	        fn into_pthread_t(self) -> RawPthread;
585	    }
586	
587	    impl<T> sealed::Sealed for ScopedJoinHandle<'_, T> {}
588	    impl<T> JoinHandleExt for ScopedJoinHandle<'_, T> {
589	        fn as_pthread_t(&self) -> RawPthread {
590	            // Borrow the handle. The handle will surely be available because the root scope waits
591	            // for nested scopes before joining remaining threads.
592	            let handle = self.handle.lock().unwrap();
593	            handle.as_ref().unwrap().as_pthread_t()
594	        }
595	        fn into_pthread_t(self) -> RawPthread {
596	            self.as_pthread_t()
597	        }
598	    }
599	}
600	/// Windows-specific extensions.
601	#[cfg(windows)]
602	mod windows {
603	    use std::os::windows::io::{AsRawHandle, IntoRawHandle, RawHandle};
604	
605	    use super::ScopedJoinHandle;
606	
607	    impl<T> AsRawHandle for ScopedJoinHandle<'_, T> {
608	        fn as_raw_handle(&self) -> RawHandle {
609	            // Borrow the handle. The handle will surely be available because the root scope waits
610	            // for nested scopes before joining remaining threads.
611	            let handle = self.handle.lock().unwrap();
612	            handle.as_ref().unwrap().as_raw_handle()
613	        }
614	    }
615	
616	    impl<T> IntoRawHandle for ScopedJoinHandle<'_, T> {
617	        fn into_raw_handle(self) -> RawHandle {
618	            self.as_raw_handle()
619	        }
620	    }
621	}
622	
623	impl<T> fmt::Debug for ScopedJoinHandle<'_, T> {
624	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
625	        f.pad("ScopedJoinHandle { .. }")
626	    }
627	}
