26	/// use crossbeam_utils::sync::WaitGroup;
27	/// use std::thread;
28	///
29	/// // Create a new wait group.
30	/// let wg = WaitGroup::new();
31	///
32	/// for _ in 0..4 {
33	///     // Create another reference to the wait group.
34	///     let wg = wg.clone();
35	///
36	///     thread::spawn(move || {
37	///         // Do some work.
38	///
39	///         // Drop the reference to the wait group.
40	///         drop(wg);
41	///     });
42	/// }
43	///
44	/// // Block until all threads have finished their work.
45	/// wg.wait();
46	/// # if cfg!(miri) { std::thread::sleep(std::time::Duration::from_millis(500)); } // wait for background threads closed: https://github.com/rust-lang/miri/issues/1371
47	/// ```
48	///
49	/// [`Barrier`]: std::sync::Barrier
50	pub struct WaitGroup {
51	    inner: Arc<Inner>,
52	}
53	
54	/// Inner state of a `WaitGroup`.
55	struct Inner {
56	    cvar: Condvar,
57	    lock: Mutex<()>,
58	    count: AtomicUsize,
59	}
60	
61	impl Default for WaitGroup {
62	    fn default() -> Self {
63	        Self {
64	            inner: Arc::new(Inner {
65	                cvar: Condvar::new(),
66	                lock: Mutex::new(()),
67	                count: AtomicUsize::new(1),
68	            }),
69	        }
70	    }
71	}
72	
73	impl WaitGroup {
74	    /// Creates a new wait group and returns the single reference to it.
75	    ///
76	    /// # Examples
77	    ///
78	    /// ```
79	    /// use crossbeam_utils::sync::WaitGroup;
80	    ///
81	    /// let wg = WaitGroup::new();
82	    /// ```
83	    pub fn new() -> Self {
84	        Self::default()
85	    }
86	
87	    /// Drops this reference and waits until all other references are dropped.
88	    ///
89	    /// # Examples
90	    ///
91	    /// ```
92	    /// use crossbeam_utils::sync::WaitGroup;
93	    /// use std::thread;
94	    ///
95	    /// let wg = WaitGroup::new();
96	    ///
97	    /// # let t =
98	    /// thread::spawn({
99	    ///     let wg = wg.clone();
100	    ///     move || {
101	    ///         // Block until both threads have reached `wait()`.
102	    ///         wg.wait();
103	    ///     }
104	    /// });
